/**
 * FlipBook Viewer - Sound Effects
 * Three real recorded page flip sounds encoded as base64
 * Uses Web Audio API for low-latency playback
 */

const FlipBookSounds = (() => {
    let audioContext = null;
    let pageFlipBuffer = null;
    let enabled = true;
    let currentSound = 'flip1';

    const SOUNDS = {
        flip1: 'data:audio/mp3;base64,',
        flip2: 'data:audio/mp3;base64,',
        flip3: 'data:audio/mp3;base64,'
    };

    async function decodeSound(key) {
        if (!audioContext || !SOUNDS[key]) return null;

        const base64Data = SOUNDS[key].split(',')[1];
        const binaryString = window.atob(base64Data);
        const len = binaryString.length;
        const bytes = new Uint8Array(len);
        for (let i = 0; i < len; i++) {
            bytes[i] = binaryString.charCodeAt(i);
        }

        try {
            return await audioContext.decodeAudioData(bytes.buffer.slice(0));
        } catch (e) {
            console.warn('Failed to decode sound:', key, e);
            return null;
        }
    }

    async function init(soundType) {
        try {
            if (!audioContext) {
                audioContext = new (window.AudioContext || window.webkitAudioContext)();
            }

            if (soundType && SOUNDS[soundType]) {
                currentSound = soundType;
            }

            pageFlipBuffer = await decodeSound(currentSound);
        } catch (e) {
            console.warn('Web Audio API error:', e);
        }
    }

    async function setSound(soundType) {
        if (SOUNDS[soundType]) {
            currentSound = soundType;
            pageFlipBuffer = await decodeSound(soundType);
        }
    }

    function play() {
        if (!enabled || !audioContext || !pageFlipBuffer) return;

        if (audioContext.state === 'suspended') {
            audioContext.resume();
        }

        const source = audioContext.createBufferSource();
        source.buffer = pageFlipBuffer;

        // Subtle random variation so it never sounds identical
        source.playbackRate.value = 0.94 + Math.random() * 0.12;

        const gainNode = audioContext.createGain();
        gainNode.gain.value = 0.7;

        source.connect(gainNode);
        gainNode.connect(audioContext.destination);
        source.start(0);
    }

    function setEnabled(state) {
        enabled = state;
    }

    function isEnabled() {
        return enabled;
    }

    function getCurrentSound() {
        return currentSound;
    }

    return { init, play, setEnabled, isEnabled, setSound, getCurrentSound };
})();
